  1	import * as React from 'react';
  2	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
  3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  4	import * as _ from 'lodash-es';
  5	import {
  6	  FormGroup,
  7	  FormHelperText,
  8	  HelperText,
  9	  HelperTextItem,
 10	  TextInput,
 11	  ValidatedOptions,
 12	} from '@patternfly/react-core';
 13	import { validateConnectionName } from '../../constants';
 14	import { HpcsConfig, HPCSParams, ProviderNames } from '../../types';
 15	import { KMSConfigureProps } from './providers';
 16	import { kmsConfigValidation, isValidName } from './utils';
 17	import './kms-config.scss';
 18	
 19	const IBM_TOKEN_URL = 'https://iam.cloud.ibm.com/oidc/token';
 20	
 21	export const HpcsConfigure: React.FC<KMSConfigureProps> = ({
 22	  state,
 23	  dispatch,
 24	  className,
 25	}) => {
 26	  const { t } = useCustomTranslation();
 27	
 28	  const kms = useDeepCompareMemoize(
 29	    state.kms.providerState,
 30	    true
 31	  ) as HpcsConfig;
 32	  const kmsObj: HpcsConfig = React.useMemo(() => _.cloneDeep(kms), [kms]);
 33	
 34	  React.useEffect(() => {
 35	    const hasHandled: boolean = kmsConfigValidation(kms, ProviderNames.HPCS);
 36	    if (kms.hasHandled !== hasHandled)
 37	      dispatch({
 38	        type: 'securityAndNetwork/setKmsProviderState',
 39	        payload: {
 40	          ...kms,
 41	          hasHandled,
 42	        },
 43	      });
 44	  }, [dispatch, kms]);
 45	
 46	  const setParams =
 47	    (param: string, isRequired: boolean = true) =>
 48	    (value: string) => {
 49	      if (isRequired) {
 50	        const validParam: boolean =
 51	          param === HPCSParams.NAME ? isValidName(value) : true;
 52	        kmsObj[param].value = value;
 53	        kmsObj[param].valid = validParam;
 54	      } else {
 55	        kmsObj[param] = value;
 56	      }
 57	      dispatch({
 58	        type: 'securityAndNetwork/setKmsProviderState',
 59	        payload: kmsObj,
 60	      });
 61	    };
 62	
 63	  const isValid = (value: boolean) =>
 64	    value ? ValidatedOptions.default : ValidatedOptions.error;
 65	
 66	  return (
 67	    <>
 68	      <FormGroup
 69	        fieldId="kms-service-name"
 70	        label={t('Connection name')}
 71	        className={`${className}__form-body`}
 72	        isRequired
 73	      >
 74	        <TextInput
 75	          value={kms.name.value}
 76	          onChange={(_ev, value) => setParams(HPCSParams.NAME)(value)}
 77	          type="text"
 78	          id="kms-service-name"
 79	          name="kms-service-name"
 80	          isRequired
 81	          validated={isValid(kms.name.valid)}
 82	          data-test="kms-service-name-text"
 83	        />
 84	
 85	        <FormHelperText>
 86	          <HelperText>
 87	            <HelperTextItem variant={isValid(kms.name.valid)}>
 88	              {isValid(kms.name.valid) === ValidatedOptions.default
 89	                ? t(
 90	                    'An unique name for the key management service within the project. Name must only include alphanumeric characters, "-", "_" or "."'
 91	                  )
 92	                : validateConnectionName(kms.name.value, t)}
 93	            </HelperTextItem>
 94	          </HelperText>
 95	        </FormHelperText>
 96	      </FormGroup>
 97	      <FormGroup
 98	        fieldId="kms-instance-id"
 99	        label={t('Service instance ID')}
100	        className={`${className}__form-body`}
101	        isRequired
102	      >
103	        <TextInput
104	          value={kms.instanceId.value}
105	          onChange={(_ev, value) => setParams(HPCSParams.INSTANCE_ID)(value)}
106	          type="text"
107	          id="kms-instance-id"
108	          name="kms-instance-id"
109	          isRequired
110	          validated={isValid(kms.instanceId.valid)}
111	          data-test="kms-instance-id-text"
112	        />
113	        <FormHelperText>
114	          <HelperText>
115	            {isValid(kms.instanceId.valid) === ValidatedOptions.error && (
116	              <HelperTextItem variant={isValid(kms.instanceId.valid)}>
117	                {t('This is a required field')}
118	              </HelperTextItem>
119	            )}
120	          </HelperText>
121	        </FormHelperText>
122	      </FormGroup>
123	      <FormGroup
124	        fieldId="kms-api-key"
125	        label={t('Service API key')}
126	        className={`${className}__form-body`}
127	        isRequired
128	      >
129	        <TextInput
130	          value={kms.apiKey.value}
131	          onChange={(_ev, value) => setParams(HPCSParams.API_KEY)(value)}
132	          type="text"
133	          id="kms-api-key"
134	          name="kms-api-key"
135	          isRequired
136	          validated={isValid(kms.apiKey.valid)}
137	          data-test="kms-api-key-text"
138	        />
139	        <FormHelperText>
140	          <HelperText>
141	            {isValid(kms.apiKey.valid) === ValidatedOptions.error && (
142	              <HelperTextItem variant={isValid(kms.apiKey.valid)}>
143	                {t('This is a required field')}
144	              </HelperTextItem>
145	            )}
146	          </HelperText>
147	        </FormHelperText>
148	      </FormGroup>
149	      <FormGroup
150	        fieldId="kms-root-key"
151	        label={t('Customer root key')}
152	        className={`${className}__form-body`}
153	        isRequired
154	      >
155	        <TextInput
156	          value={kms.rootKey.value}
157	          onChange={(_ev, value) => setParams(HPCSParams.ROOT_KEY)(value)}
158	          type="text"
159	          id="kms-root-key"
160	          name="kms-root-key"
161	          isRequired
162	          validated={isValid(kms.rootKey.valid)}
163	          data-test="kms-root-key-text"
164	        />
165	        <FormHelperText>
166	          <HelperText>
167	            {isValid(kms.rootKey.valid) === ValidatedOptions.error && (
168	              <HelperTextItem
169	                variant={isValid(kms.rootKey.valid) ? 'default' : 'error'}
170	              >
171	                {t('This is a required field')}
172	              </HelperTextItem>
173	            )}
174	          </HelperText>
175	        </FormHelperText>
176	      </FormGroup>
177	      <FormGroup
178	        fieldId="kms-base-url"
179	        label={t('IBM base URL')}
180	        className={`${className}__form-body`}
181	        isRequired
182	      >
183	        <TextInput
184	          value={kms.baseUrl.value}
185	          onChange={(_ev, value) => setParams(HPCSParams.BASE_URL)(value)}
186	          type="text"
187	          id="kms-base-url"
188	          name="kms-base-url"
189	          isRequired
190	          validated={isValid(kms.baseUrl.valid)}
191	          data-test="kms-base-url"
192	        />
193	        <FormHelperText>
194	          <HelperText>
195	            {isValid(kms.baseUrl.valid) === ValidatedOptions.error && (
196	              <HelperTextItem variant={isValid(kms.baseUrl.valid)}>
197	                {t('This is a required field')}
198	              </HelperTextItem>
199	            )}
200	          </HelperText>
201	        </FormHelperText>
202	      </FormGroup>
203	      <FormGroup
204	        fieldId="kms-token-url"
205	        label={t('IBM token URL')}
206	        className={`${className}__form-body`}
207	      >
208	        <TextInput
209	          value={kms.tokenUrl}
210	          onChange={(_ev, value) =>
211	            setParams(HPCSParams.TOKEN_URL, false)(value)
212	          }
213	          placeholder={IBM_TOKEN_URL}
214	          type="text"
215	          id="kms-token-url"
216	          name="kms-token-url"
217	          data-test="kms-token-url"
218	        />
219	      </FormGroup>
220	    </>
221	  );
222	};

